fail_reason_1 = #{failReason1}, fail_message_1 = #{failMessage1}, fail_reason_2 = #{failReason2}, fail_message_2 = #{failMessage2}, fail_reason_3 = #{failReason3}, fail_message_3 = #{failMessage3}, fail_count = #{failCount}, status = #{status}, update_time = #{updateTime},
